final:
module top_module (
    input [1:0] m,
    output reg not_n
);

    always @(*) begin
        case (m)
            2'b00: not_n = 1;
            2'b01: not_n = 0;
            2'b10: not_n = 1;
            2'b11: not_n = 1;
            default: not_n = 0; // Default case
        endcase
    end
endmodule
